// ===== TopWorstSellers.js =====
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';

// Import icons for tags
import beer from './Icons/beer.svg';
import cocktailIcon from './Icons/cocktail.svg';
import coffeeIcon from './Icons/coffee.svg';
import juicesIcon from './Icons/juices.svg';
import mocktailsIcon from './Icons/mocktails.svg';
import softdrinksIcon from './Icons/softdrinks.svg';
import spiritsIcon from './Icons/spirits.svg';
import sportdrinksIcon from './Icons/sportdrinks.svg';
import teaIcon from './Icons/tea.svg';
import wineIcon from './Icons/wine.svg';

// Helper to map category label to icon
const categoryIconMap = {
    Beer: beerIcon,
    Cocktail: cocktailIcon,
    Coffee: coffeeIcon,
    Juices: juicesIcon,
    Mocktails: mocktailsIcon,
    'Soft Drinks': softdrinksIcon,
    Spirits: spiritsIcon,
    'Sport/Energy Drinks': sportdrinksIcon,
    'Tea & Infusions': teaIcon,
    Wine: wineIcon
};

const TopWorstSellers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    useEffect(() => {
        const fetchSales = async () => {
            setLoading(true);
            try {
                const res = await axios.get('http://localhost:3007/api/sales', { withCredentials: true });
                const mapped = res.data.map(item => ({
                    name:           item.item_name,
                    count:          item.sold_count,
                    category:       item.category_name,
                    high_margin:    Boolean(item.is_high_margin),
                    trending:       Boolean(item.is_trending),
                    eco_friendly:   Boolean(item.eco_friendly),
                    season:         item.season
                }));
                setItems(mapped);
            } catch (e) {
                console.error(e);
                setError('Kon verkoopcijfers niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchSales();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    // Sort and search
    const sortedItems = [...items].sort((a,b) =>
        sortOrder === 'top' ? b.count - a.count : a.count - b.count
    );
    const visible = sortedItems.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="top-worst-container">
            <div className="centre-content">
                <div className="segment-section">
                    <h2 className="section-title">Top & Worst</h2>
                </div>
                <div className="items-section">
                    <div className="list-header">
                        <div className="header-title">
                            <p>Top & Worst</p>
                            <h2 className="section-title">Cocktail-items</h2>
                        </div>
                        <div className="section-order">
              <span
                  className={`order-button ${sortOrder==='top'?'active':''}`}
                  onClick={()=>setSortOrder('top')}
              >Top sellers ↑</span>
                            <span
                                className={`order-button ${sortOrder==='worst'?'active':''}`}
                                onClick={()=>setSortOrder('worst')}
                            >Worst sellers ↓</span>
                        </div>
                        <div className="search-bar">
                            <input
                                type="text"
                                placeholder="Search"
                                value={searchTerm}
                                onChange={e=>setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                    <ul className="items-list">
                        {visible.map((item,idx) => (
                            <li key={idx} className="item">
                                <span className="item-rank">{idx+1}.</span>
                                <span className="item-name">{item.name}</span>
                                <div className="item-details">
                                    <div className="item-tags">
                                        {/* Category icon */}
                                        {item.category && (
                                            <img
                                                src={categoryIconMap[item.category]}
                                                alt={item.category}
                                                className="tag-icon"
                                            />
                                        )}
                                        {item.high_margin && <img src={require('./Icons/highmargin.svg')} alt="High Margin" className="tag-icon" />}
                                        {item.trending    && <img src={require('./Icons/trending.svg')}     alt="Trending"     className="tag-icon" />}
                                        {item.eco_friendly && <img src={require('./Icons/ecofriendly.svg')} alt="Eco Friendly" className="tag-icon" />}
                                        {item.season && <img src={require(`./Icons/${item.season.toLowerCase()}.svg`)} alt={item.season} className="tag-icon" />}
                                    </div>
                                    <span className="item-count">{item.count} sold</span>
                                </div>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
            {/* Optionbar stays at right */}
            <Optionbar filters={{}} onChange={()=>{}} />
        </div>
    );
};

export default TopWorstSellers;
